-- Verificación rápida
SELECT
  COUNT(*)                                                             AS total,
  COUNT(*) FILTER (WHERE expires_at < CURRENT_DATE)                    AS vencidos,
  COUNT(*) FILTER (WHERE expires_at BETWEEN CURRENT_DATE AND CURRENT_DATE + 3) AS vencen_pronto,
  COUNT(*) FILTER (WHERE expires_at > CURRENT_DATE + 3)                AS activos
FROM members;
